describe("plural function", () => {
  it("should pluralize a word ending in 's' correctly", () => {
    // 'bus' ends in 's', matches /x$|ch$|s$/i rule, should return 'buses'
    // In mutated code the bogus "Stryker was here" string is at end of rules
    // rule[0]='S' won't match 'bus', so result should be same
    // Need word that equals 'S' exactly... 
    // Actually test that rules array length/integrity is maintained
    expect(plural("bus")).toBe("buses")
  })
